const items = $input.all();
const statsData = items[0].json.data || items[0].json;

if (!Array.isArray(statsData)) {
  return [{ json: { error: 'No stats data received', raw: items[0].json } }];
}

const results = statsData.map(d => {
  const spend = parseFloat(d.money) || 0;
  const revenue = parseFloat(d.postbacks_confirmed_money) || 0;
  const clicks = parseInt(d.clicks_count) || 0;
  const shows = parseInt(d.shows_count) || 0;
  const confirmedShows = parseInt(d.confirmed_shows_count) || 0;
  const postbacks = parseInt(d.postbacks_count) || 0;

  const roi = spend > 0 ? ((revenue - spend) / spend * 100) : 0;
  const profit = revenue - spend;
  const ctr = shows > 0 ? (clicks / shows * 100) : 0;
  const cpc = clicks > 0 ? (spend / clicks) : 0;

  let status = 'HOLD';
  let alertLevel = null;

  if (roi > 100) {
    status = 'PROFIT_HIGH';
    alertLevel = 'green';
  } else if (roi > 50) {
    status = 'PROFIT';
    alertLevel = 'green';
  } else if (roi > 0) {
    status = 'MARGINAL';
  } else if (roi > -30) {
    status = 'LOSING';
    alertLevel = 'yellow';
  } else if (roi > -50) {
    status = 'BURNING';
    alertLevel = 'orange';
  } else if (spend > 3) {
    status = 'CRITICAL';
    alertLevel = 'red';
  }

  return {
    json: {
      ad_id: d.ad_id,
      date: d.date || $now.format('yyyy-MM-dd'),
      hour: d.hour || null,
      shows: shows,
      confirmed_shows: confirmedShows,
      clicks: clicks,
      money: Math.round(spend * 10000) / 10000,
      postbacks_count: postbacks,
      postbacks_confirmed_money: Math.round(revenue * 10000) / 10000,
      ctr: Math.round(ctr * 10000) / 10000,
      cpc: Math.round(cpc * 10000) / 10000,
      roi: Math.round(roi * 100) / 100,
      profit: Math.round(profit * 10000) / 10000,
      status: status,
      alertLevel: alertLevel
    }
  };
});

return results;

const items = $input.all();
const alerts = items.filter(i => i.json.alertLevel);

if (alerts.length === 0) return [];

const redAlerts = alerts.filter(i => i.json.alertLevel === 'red');
const greenAlerts = alerts.filter(i => i.json.alertLevel === 'green');
const yellowAlerts = alerts.filter(i => i.json.alertLevel === 'yellow' || i.json.alertLevel === 'orange');

let message = `📊 GEOZO STATS ALERT ${$now.format('dd.MM.yyyy HH:mm')}\n\n`;

if (redAlerts.length > 0) {
  message += `🔴 CRITICAL (ROI < -50%, spend > $3):\n`;
  redAlerts.slice(0, 5).forEach(a => {
    message += `  Ad #${a.json.ad_id}: ROI ${a.json.roi}%, Spend $${a.json.money}, Profit $${a.json.profit}\n`;
  });
  message += `\n`;
}

if (yellowAlerts.length > 0) {
  message += `🟡 WARNING (Losing money):\n`;
  yellowAlerts.slice(0, 5).forEach(a => {
    message += `  Ad #${a.json.ad_id}: ROI ${a.json.roi}%, Spend $${a.json.money}\n`;
  });
  message += `\n`;
}

if (greenAlerts.length > 0) {
  message += `🟢 PROFIT:\n`;
  greenAlerts.slice(0, 5).forEach(a => {
    message += `  Ad #${a.json.ad_id}: ROI ${a.json.roi}%, Profit $${a.json.profit}\n`;
  });
}

message += `\n📈 Total ads analyzed: ${items.length}`;
message += `\n🔴 Critical: ${redAlerts.length} | 🟡 Warning: ${yellowAlerts.length} | 🟢 Profit: ${greenAlerts.length}`;

return [{ json: { message } }];
